import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicLong;
import java.util.List;
import java.util.ArrayList;
import java.util.Collections;

public class AdvancedTaskScheduler {
    private final ThreadPoolExecutor executor;
    private final AtomicLong completedTasks = new AtomicLong(0);
    private final List<String> taskHistory = Collections.synchronizedList(new ArrayList<>());

    public AdvancedTaskScheduler(int corePoolSize, int maxPoolSize, long keepAliveTime, TimeUnit unit) {
        this.executor = new ThreadPoolExecutor(
            corePoolSize,
            maxPoolSize,
            keepAliveTime,
            unit,
            new LinkedBlockingQueue<Runnable>(100),
            new CustomThreadFactory("TaskWorker"),
            new ThreadPoolExecutor.CallerRunsPolicy()
        );
        System.out.println("TaskScheduler initialized with core: " + corePoolSize + ", max: " + maxPoolSize);
    }

    public Future<String> submitTask(String taskName, Callable<String> task) {
        return executor.submit(() -> {
            try {
                System.out.println("Executing task: " + taskName);
                String result = task.call();
                completedTasks.incrementAndGet();
                taskHistory.add(taskName + ": " + result);
                return result;
            } catch (Exception e) {
                System.err.println("Task '" + taskName + "' failed: " + e.getMessage());
                throw e;
            }
        });
    }

    public long getCompletedTaskCount() {
        return completedTasks.get();
    }

    public List<String> getTaskHistory() {
        return new ArrayList<>(taskHistory);
    }

    public void shutdown() {
        System.out.println("Shutting down TaskScheduler...");
        executor.shutdown();
        try {
            if (!executor.awaitTermination(60, TimeUnit.SECONDS)) {
                executor.shutdownNow();
                if (!executor.awaitTermination(60, TimeUnit.SECONDS)) {
                    System.err.println("Scheduler did not terminate");
                }
            }
        } catch (InterruptedException ie) {
            executor.shutdownNow();
            Thread.currentThread().interrupt();
        }
        System.out.println("TaskScheduler shut down.");
    }

    private static class CustomThreadFactory implements ThreadFactory {
        private final String namePrefix;
        private final AtomicLong count = new AtomicLong(0);

        public CustomThreadFactory(String namePrefix) {
            this.namePrefix = namePrefix;
        }

        @Override
        public Thread newThread(Runnable r) {
            Thread t = new Thread(r, namePrefix + "-" + count.incrementAndGet());
            t.setDaemon(false);
            return t;
        }
    }

    public static void main(String[] args) throws Exception {
        AdvancedTaskScheduler scheduler = new AdvancedTaskScheduler(2, 4, 10, TimeUnit.SECONDS);

        List<Future<String>> results = new ArrayList<>();
        for (int i = 0; i < 5; i++) {
